function touch { New-Item -ItemType File -Path $args[0] -Force | Out-Null }
function which { (Get-Command $args[0]).Source }
Set-Alias -Name grep -Value Select-String
function Reload-Profile { . $PROFILE }

function Get-EnvVar { [System.Environment]::GetEnvironmentVariables() }
function Set-EnvVar($name, $val) { [System.Environment]::SetEnvironmentVariable($name, $val, 'User') }
function Remove-EnvVar($name) { [System.Environment]::SetEnvironmentVariable($name, $null, 'User') }

function dev { Set-Location "$HOME\dev" }
function desk { Set-Location "$HOME\Desktop" }
function dl { Set-Location "$HOME\Downloads" }
Set-Alias -Name back -Value { Set-Location .. }
